  await page.goto('http://localhost:5173/todos', { waitUntil: 'networkidle0' });

  // Check the page content
  const html = await page.content();
  console.log('Has Add Todo button:', html.includes('Add Todo'));
  console.log('Has title input:', html.includes('name=\"title\"'));

  // Reset todos
  const resetRes = await fetch('http://localhost:5173/todos.reset', { method: 'POST' });
  console.log('Reset:', await resetRes.text());

